const WARM = ['#e8d4a0', '#c4894a', '#8b4a2a', '#f5e6c8', '#d4a574'];
const COOL = ['#4a6670', '#8a9ba0'];
const SHADOW = '#2a1f14';
let ripples = [];
let lastSpawn = 0;

function setup(){ createCanvas(800, 800); noFill(); }

function draw(){
  // a slow ripple expanding across a dark pool
  background(SHADOW + '22');
  const amp = (window.features && window.features.amplitude) || 0;
  const intensity = (window.features && window.features.hijaz_intensity) || 0;
  const onset = (window.features && window.features.onset_strength) || 0;

  const cx = width / 2;
  const cy = height * 0.62;

  // spawn a ripple every ~1.6s, sooner on stronger onsets
  const interval = 1600 - onset * 600;
  if (millis() - lastSpawn > interval) {
    ripples.push({ r: 6, life: 1, jitter: 0.6 + intensity * 0.4 });
    lastSpawn = millis();
  }

  // dark water sheen — a soft horizontal band of pale candlelight reflection
  push();
  noStroke();
  for (let i = 0; i < 8; i++) {
    fill(245, 230, 200, 6 - i * 0.5);
    ellipse(cx, cy, 520 - i * 30, 18 - i);
  }
  pop();

  // ripples
  for (let i = ripples.length - 1; i >= 0; i--) {
    const rp = ripples[i];
    rp.r += 0.9 + amp * 0.6;
    rp.life -= 0.006;
    if (rp.life <= 0) { ripples.splice(i, 1); continue; }
    stroke(245, 230, 200, 180 * rp.life);
    strokeWeight(1.2);
    ellipse(cx, cy, rp.r * 2, rp.r * 0.55);
    stroke(212, 165, 116, 90 * rp.life);
    strokeWeight(0.6);
    ellipse(cx, cy, rp.r * 2.2, rp.r * 0.6);
  }

  // a single thin line of moonlight catching the surface center
  stroke(245, 230, 200, 200);
  strokeWeight(1.4);
  line(cx - 80, cy, cx + 80, cy);
  stroke(232, 212, 160, 80);
  strokeWeight(3);
  line(cx - 40, cy, cx + 40, cy);
}
